namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh tomatoes, mozzarella, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                    "Stretch dough into a 12-inch round on a floured surface.",
                    "Spread crushed tomatoes evenly over the dough.",
                    "Tear mozzarella into pieces and distribute over the sauce.",
                    "Bake for 10-12 minutes until crust is golden and cheese is bubbly.",
                    "Top with fresh basil leaves and a drizzle of olive oil."
                ],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy pasta with pancetta, eggs, and Pecorino Romano.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "While pasta cooks, fry pancetta until crispy.",
                    "Whisk eggs with grated Pecorino and plenty of black pepper.",
                    "Drain pasta, reserving 1 cup of pasta water.",
                    "Toss hot pasta with pancetta, then quickly stir in egg mixture.",
                    "Add pasta water as needed for a creamy consistency."
                ],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cumin", "Turmeric"],
                Steps = [
                    "Marinate chicken in yogurt, garam masala, and salt for 1 hour.",
                    "Grill or broil chicken until lightly charred.",
                    "Sauté onion, garlic, and ginger in a large pan.",
                    "Add spices and cook for 1 minute until fragrant.",
                    "Add tomato sauce and simmer for 15 minutes.",
                    "Stir in cream and add the cooked chicken. Simmer 10 minutes."
                ],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Biryani", Category = "Indian",
                Description = "Fragrant basmati rice layered with spiced vegetables.",
                Ingredients = ["Basmati rice", "Mixed vegetables", "Onion", "Yogurt", "Saffron", "Whole spices", "Ghee", "Mint", "Cilantro"],
                Steps = [
                    "Soak basmati rice for 30 minutes, then parboil.",
                    "Sauté sliced onions in ghee until golden brown.",
                    "Add vegetables and spices, cook for 5 minutes.",
                    "Layer rice and vegetable mixture in a heavy pot.",
                    "Add saffron milk, mint, and cilantro between layers.",
                    "Cover tightly and cook on low heat for 20 minutes."
                ],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in crispy tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning", "Onion"],
                Steps = [
                    "Brown ground beef with diced onion in a skillet.",
                    "Add taco seasoning and water, simmer until thickened.",
                    "Warm taco shells in the oven for 3 minutes.",
                    "Fill shells with seasoned beef.",
                    "Top with shredded lettuce, diced tomato, cheese, and sour cream."
                ],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and creamy avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt", "Garlic"],
                Steps = [
                    "Halve and pit ripe avocados, scoop into a bowl.",
                    "Mash with a fork to desired consistency.",
                    "Stir in lime juice, minced garlic, and salt.",
                    "Fold in diced onion, tomato, jalapeño, and cilantro.",
                    "Taste and adjust seasoning. Serve immediately with chips."
                ],
                TotalRatings = 20, RatingSum = 90
            },
            new Recipe
            {
                Id = 7, Title = "Teriyaki Salmon", Category = "Japanese",
                Description = "Glazed salmon fillets with a sweet and savory teriyaki sauce.",
                Ingredients = ["Salmon fillets", "Soy sauce", "Mirin", "Sugar", "Ginger", "Garlic", "Sesame seeds", "Green onion"],
                Steps = [
                    "Mix soy sauce, mirin, sugar, ginger, and garlic for the glaze.",
                    "Pat salmon dry and season with salt and pepper.",
                    "Sear salmon skin-side up in a hot skillet for 3 minutes.",
                    "Flip and pour teriyaki glaze over the salmon.",
                    "Cook for 3-4 more minutes, spooning glaze over the fish.",
                    "Garnish with sesame seeds and sliced green onion."
                ],
                TotalRatings = 9, RatingSum = 41
            },
            new Recipe
            {
                Id = 8, Title = "Miso Soup", Category = "Japanese",
                Description = "A comforting Japanese soup with tofu, seaweed, and miso paste.",
                Ingredients = ["Dashi stock", "White miso paste", "Silken tofu", "Wakame seaweed", "Green onion"],
                Steps = [
                    "Bring dashi stock to a gentle simmer.",
                    "Rehydrate wakame seaweed in warm water, then drain.",
                    "Cut tofu into small cubes.",
                    "Dissolve miso paste in a ladleful of hot dashi, then stir into the pot.",
                    "Add tofu and wakame. Heat gently without boiling.",
                    "Serve garnished with sliced green onion."
                ],
                TotalRatings = 7, RatingSum = 30
            },
        ];
        _nextId = 9;
    }

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

@using RecipeHub.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "hovered" : "") @(star <= _selectedStar ? "selected" : "")"
              @onmouseover="() => _hoveredStar = star"
              @onmouseout="() => _hoveredStar = 0"
              @onclick="() => SubmitRating(star)"
              role="button"
              title="Rate @star star@(star > 1 ? "s" : "")">
            @(star <= (_hoveredStar > 0 ? _hoveredStar : _selectedStar) ? "★" : "☆")
        </span>
    }
    @if (_submitted)
    {
        <span class="rating-thanks">Thanks for rating!</span>
    }
    <span class="rating-info">@AverageDisplay</span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int CurrentCount { get; set; }

    private int _hoveredStar;
    private int _selectedStar;
    private bool _submitted;
    private double _displayAverage;
    private int _displayCount;

    protected override void OnParametersSet()
    {
        _displayAverage = CurrentAverage;
        _displayCount = CurrentCount;
    }

    private string AverageDisplay =>
        _displayCount > 0 ? $"{_displayAverage:F1} avg ({_displayCount} ratings)" : "No ratings yet";

    private void SubmitRating(int stars)
    {
        if (_submitted) return;
        _selectedStar = stars;
        _submitted = true;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            _displayAverage = recipe.AverageRating;
            _displayCount = recipe.TotalRatings;
        }
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 0.15rem;
    margin: 1rem 0;
}

.star {
    font-size: 1.8rem;
    color: #ccc;
    cursor: pointer;
    transition: color 0.15s, transform 0.15s;
    user-select: none;
}

.star.hovered,
.star.selected {
    color: #f5a623;
}

.star:hover {
    transform: scale(1.2);
}

.rating-thanks {
    margin-left: 0.75rem;
    color: #28a745;
    font-weight: 500;
    font-size: 0.9rem;
}

.rating-info {
    margin-left: 0.75rem;
    color: #6c757d;
    font-size: 0.85rem;
}

namespace RecipeHub.Models;

