﻿@page "/"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>RecipeHub - Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 Welcome to RecipeHub</h1>
    <p class="lead">Discover, share, and rate recipes from around the world.</p>
</div>

<h2 class="mb-3">Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-3 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h3 class="card-title">@CategoryEmoji(category) @category</h3>
                    <p class="card-text text-muted">
                        @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                    </p>
                    <a href="/category/@category" class="btn btn-outline-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

<div class="mt-4 text-center">
    <a href="/submit" class="btn btn-success btn-lg">📝 Submit a Recipe</a>
</div>

@code {
    private static string CategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Japanese" => "🍣",
        _ => "🍽️"
    };
}

