@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted mb-2">
                            @if (recipe.TotalRatings > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.TotalRatings ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<RecipeHub.Models.Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (_recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        }
    </ol>
</nav>

@if (_recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@_recipe.Title</h1>
    <p class="lead text-muted">@_recipe.Description</p>

    <StarRating RecipeId="@_recipe.Id"
                CurrentAverage="@_recipe.AverageRating"
                CurrentCount="@_recipe.TotalRatings" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">🥘 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">📋 Steps</h5></div>
                <div class="card-body">
                    <ol class="mb-0">
                        @foreach (var step in _recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeHub.Models.Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@_submission.Title</strong>" has been added.
        <a href="/recipe/@_newRecipeId">View it here</a>.
    </div>
}

<EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="_submission.Title"
                   placeholder="e.g., Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="_submission.Category">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="Other">Other</option>
        </InputSelect>
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients</label>
        <InputTextArea id="ingredients" class="form-control" rows="6"
                       @bind-Value="_submission.Ingredients"
                       placeholder="Enter one ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        <div class="form-text">Enter one ingredient per line.</div>
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps</label>
        <InputTextArea id="steps" class="form-control" rows="6"
                       @bind-Value="_submission.Steps"
                       placeholder="Enter one step per line&#10;e.g.,&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients and stir" />
        <div class="form-text">Enter one step per line.</div>
    </div>

    <button type="submit" class="btn btn-success"
            disabled="@(string.IsNullOrWhiteSpace(_submission.Title) ||
                        string.IsNullOrWhiteSpace(_submission.Category) ||
                        string.IsNullOrWhiteSpace(_submission.Ingredients) ||
