        <InputTextArea id="steps" class="form-control" rows="6"
                       @bind-Value="_submission.Steps"
                       placeholder="Enter one step per line&#10;e.g.,&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients and stir" />
        <div class="form-text">Enter one step per line.</div>
    </div>

    <button type="submit" class="btn btn-success"
            disabled="@(string.IsNullOrWhiteSpace(_submission.Title) ||
                        string.IsNullOrWhiteSpace(_submission.Category) ||
                        string.IsNullOrWhiteSpace(_submission.Ingredients) ||
                        string.IsNullOrWhiteSpace(_submission.Steps))">
        Submit Recipe
    </button>
</EditForm>

@code {
    private RecipeSubmission _submission = new();
    private bool _submitted;
    private int _newRecipeId;

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(_submission);
        _newRecipeId = recipe.Id;
        _submitted = true;
    }
}

